#include<cstdio>
#include<cstring>
#include<vector>
#define rep(a,b,c) for(int c=(a);c<=(b);++c)
#define grep(a,b,c) for(int c=a.head[(b)];c;c=a.nxt[c])
using namespace std;
inline int read()
{
	int res=0;char ch=getchar();bool flag=0;
	while(ch<'0'||ch>'9')flag^=(ch=='-'),ch=getchar();
	while(ch<='9'&&ch>='0')res=res*10+(ch^48),ch=getchar();
	return flag ? -res : res;
}
inline void Swap(int &x,int &y){int tmp=x;x=y;y=tmp;}
const int N=1e6+10,Mod=1e9+7;
struct Graph
{
	int head[N],nxt[N],des[N],cnt;
	inline void ins(int x,int y){nxt[++cnt]=head[x];des[cnt]=y;head[x]=cnt;}
}a;
vector<int> pre[N];int res[N];
struct ACAM
{
	int que[N],H,T,ch[N][26],hsh[N],nxt[N],cnt;
	inline void ins(char *s,int n)
	{
		int len=strlen(s),p=0,hsh=0;pre[n].push_back(0);
		rep(0,len-1,i)
		{
			int &x=ch[p][s[i]-'a'];p=(x?x:x=++cnt);
			pre[n].push_back(p);res[p]=hsh=(1ll*hsh*26+(s[i]-'a'))%Mod;
		}
	}
	inline void build()
	{
		que[H=T=1]=0;while(H<=T)
		{
			int u=que[H++];if(!u)rep(0,25,i)if(ch[0][i])que[++T]=ch[0][i];
			if(u)rep(0,25,i)!ch[u][i]?ch[u][i]=ch[nxt[u]][i]:(nxt[que[++T]=ch[u][i]]=ch[nxt[u]][i]);
		}
		rep(1,cnt,i)a.ins(nxt[i],i);
	}
}A;
char ch[N];int siz[N],dep[N],mxs[N],fa[N],top[N];
inline void dfs0(int u)
{
	siz[u]=1;int mx=0;grep(a,u,i)
	{
		int v=a.des[i];dep[v]=dep[u]+1;
		dfs0(v);siz[u]+=siz[v];fa[v]=u;
		siz[v]>mx?mx=siz[v],mxs[u]=v:0;
	}
}
inline void dfs1(int u,int tp)
{
	top[u]=tp;if(mxs[u])dfs1(mxs[u],tp);
	grep(a,u,i){int v=a.des[i];if(v==mxs[u])continue;dfs1(v,v);}
}
inline int LCA(int x,int y)
{
	while(top[x]^top[y])
	{
		if(dep[top[x]]<dep[top[y]])Swap(x,y);
		x=fa[top[x]];
	}
	return dep[x]<dep[y]?x:y;
}
inline void debug(int k){if(k>25)debug(k/26);putchar(k%26+'a');}
inline void print(int u){printf("tmd %d\n",u);grep(a,u,i){int v=a.des[i];print(v);printf("%d %d\n",u,v);}}
int main()
{
	int n=read();rep(1,n,i)scanf("%s",ch),A.ins(ch,i);
	A.build();dep[0]=1;dfs0(0);dfs1(0,0);//print(0);
	int m=read();rep(1,m,i)
	{
		int x1=read(),y1=read(),x2=read(),y2=read();
		int ans=res[LCA(pre[x1][y1],pre[x2][y2])];printf("%d\n",ans);
	}
}
